sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {

    // الحصول على reqSysId من الحدث (الذي بعثته Business Rule)
    var reqSysId = event.parm1;
    if (!reqSysId) {
        template.print('<p style="color:red;">Error: No REQ sys_id provided.</p>');
        return;
    }

    // جلب بيانات REQ (للحصول على رقم الطلب الحقيقي)
    var reqGr = new GlideRecord('sc_request');
    reqGr.get(reqSysId);
    var reqNumber = reqGr.number.toString();

    // بناء قائمة الأدوية بتنسيق HTML
    var medicinesHTML = '';
    var medGr = new GlideRecord('x_1971078_smart_0_medicine_inventory');
    var ritms = new GlideRecord('sc_req_item');
    ritms.addQuery('request', reqSysId);
    ritms.query();

    while (ritms.next()) {
        var medSysId = ritms.variables.medicine_name;
        var qty = ritms.variables.quantity_needed || '?';
        var state = ritms.approval_state.toString();

        var medName = 'Unknown';
        if (medGr.get(medSysId)) medName = medGr.medicine_name.toString();

        var statusText = '';
        if (state == 'approved') statusText = '✅ Approved';
        else if (state == 'rejected') statusText = '❌ Rejected';
        else if (state == 'not_required') statusText = '❌ Auto-rejected (timeout)';

        medicinesHTML += '<tr style="border-bottom: 1px solid #E2E8F0;">' +
                         '<td style="padding: 12px 8px; color: #0F172A;">' + medName + '</td>' +
                         '<td style="padding: 12px 8px; text-align: center; color: #0F172A;">' + qty + '</td>' +
                         '<td style="padding: 12px 8px; text-align: center;">' + statusText + '</td>' +
                         '</tr>';
    }

    // طباعة الجدول (هذا هو الجزء الذي سيتم إدراجه في الإيميل)
    template.print(medicinesHTML);

})(current, template, email, email_action, event);
